import React, { useState, useEffect, useRef } from 'react';
import './Work.css';

const FILTERS = ['All', 'YouTube', 'Brand', 'Short Film', 'Music Video', 'Documentary'];

const PROJECTS = [
  { id: 1, title: "Mark Cuban's Journey to Billionaire Status", cat: 'YouTube',     views: '2.1M views', year: '2024', dur: '3:42', span: 5, row: 2, th: 'th-2', label: 'HUSTLE' },
  { id: 2, title: 'Apple × Creators 2024',                     cat: 'Brand',        views: 'Brand Campaign', year: '', dur: '1:30', span: 4, row: 1, th: 'th-1', label: 'BRAND' },
  { id: 3, title: 'Afterglow — Official MV',                   cat: 'Music Video',  views: '540K views', year: '', dur: '4:17', span: 3, row: 1, th: 'th-5', label: 'VIBE' },
  { id: 4, title: 'The Secret to Retaining Younger Talent',    cat: 'Documentary',  views: '890K views', year: '2023', dur: '8:14', span: 4, row: 1, th: 'th-3', label: 'NERVE' },
  { id: 5, title: 'Post Breakup Emotions',                     cat: 'Short Film',   views: 'Narrative', year: '', dur: '2:55', span: 3, row: 1, th: 'th-7', label: 'WILD' },
  { id: 6, title: 'The Kokoda Campaign',                       cat: 'YouTube',      views: '1.2M views', year: '', dur: '6:30', span: 3, row: 1, th: 'th-6', label: 'OVER' },
  { id: 7, title: 'Delwinder — The Untold Story',              cat: 'Documentary',  views: 'Sports Doc', year: '2024', dur: '10:22', span: 6, row: 1, th: 'th-4', label: 'DELWINDER' },
  { id: 8, title: 'Max Verstappen Edit',                       cat: 'Brand',        views: 'F1 Fan Film', year: '', dur: '3:10', span: 3, row: 1, th: 'th-8', label: 'MAX' },
];

const CAT_CLASS = {
  'YouTube':     'cat-yt',
  'Brand':       'cat-brand',
  'Documentary': 'cat-doc',
  'Music Video': 'cat-music',
  'Short Film':  'cat-short',
};

export default function Work() {
  const [active, setActive] = useState('All');
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) el.querySelectorAll('.reveal').forEach(r => r.classList.add('visible'));
    }, { threshold: 0.05 });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  const visible = active === 'All' ? PROJECTS : PROJECTS.filter(p => p.cat === active);

  return (
    <section className="section" id="work" ref={ref}>
      <div className="sec-header">
        <p className="sec-tag reveal">02 — Selected Work</p>
        <h2 className="sec-title reveal">My Work</h2>
        <p className="sec-sub reveal">Hover to preview · Click to watch</p>
      </div>

      <div className="filter-tabs reveal">
        {FILTERS.map(f => (
          <button
            key={f}
            className={`ftab ${active === f ? 'active' : ''}`}
            onClick={() => setActive(f)}
          >
            {f}
          </button>
        ))}
      </div>

      <div className="bento reveal">
        {visible.map(p => (
          <div
            key={p.id}
            className={`bcard span-${p.span} row-${p.row}`}
          >
            <div className={`bcard-thumb ${p.th}`}>
              <div className="th-shape">{p.label}</div>
            </div>
            <span className="bcard-corner">{p.dur}</span>
            <div className="bcard-overlay">
              <span className={`bcard-cat ${CAT_CLASS[p.cat]}`}>{p.cat}</span>
              <div className="bcard-title">{p.title}</div>
              <div className="bcard-meta">
                <span>{p.views}</span>
                {p.year && <><span>·</span><span>{p.year}</span></>}
              </div>
            </div>
            <div className="bplay">
              <svg width="14" height="14" viewBox="0 0 14 14" fill="currentColor">
                <polygon points="3,1 13,7 3,13" />
              </svg>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
